import argparse
import json
import pickle
from pathlib import Path
from collections import defaultdict
import numpy as np
import heapq
import glob
from cogniplan_env import ExplorationEnv

def load_model(checkpoint_dir):
    checkpoint_dir = Path(checkpoint_dir)
    model_path = checkpoint_dir / "model.pkl"
    if model_path.exists():
        with open(model_path, "rb") as f:
            return pickle.load(f)
    return {"type": "heuristic_utility_over_dist", "alpha": 3.0, "beta": 1.8}

def get_env_type(map_path):
    pstr = str(map_path).lower()
    if 'room' in pstr: return 'room'
    if 'tunnel' in pstr: return 'tunnel'
    if 'outdoor' in pstr: return 'outdoor'
    return 'room'

def select_waypoint(obs, model):
    neighbors = obs.get("neighbors", [])
    if not neighbors:
        return None
    nodes = obs.get("nodes", [])
    if not nodes:
        return neighbors[0] if neighbors else None

    def coord_to_tuple(c):
        if isinstance(c, np.ndarray):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        if isinstance(c, (list, tuple)):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        return c

    node_dict = {}
    for node in nodes:
        coords = coord_to_tuple(node.get("coords"))
        if coords is not None:
            node_dict[coords] = node

    current_pos = coord_to_tuple(obs.get("robot_pos", np.array([0.0, 0.0])))
    if current_pos not in node_dict:
        min_d = float('inf')
        closest = None
        for nc in node_dict:
            d = ((nc[0] - current_pos[0]) ** 2 + (nc[1] - current_pos[1]) ** 2 ) ** 0.5
            if d < min_d:
                min_d = d
                closest = nc
        if closest is not None:
            current_pos = closest

    if current_pos not in node_dict:
        best_utility = -1.0
        best_target = neighbors[0]
        for n in neighbors:
            nc = coord_to_tuple(n)
            u = node_dict.get(nc, {}).get("utility", 0.0) if nc in node_dict else 0.0
            if u > best_utility:
                best_utility = u
                best_target = n
        return best_target

    graph = {}
    utilities = {}
    visited_flags = {}
    for coord, node in node_dict.items():
        neighs = [coord_to_tuple(n) for n in node.get("neighbors", [])]
        graph[coord] = [n for n in neighs if n in node_dict]
        utilities[coord] = float(node.get("utility", 0.0))
        visited_flags[coord] = bool(node.get("visited", False))

    def get_edge_distance(a, b):
        return ((a[0] - b[0]) ** 2 + (a[1] - b[1]) ** 2 ) ** 0.5

    def shortest_path_distance(start, goal):
        if start == goal:
            return 0.0
        pq = [(0.0, start)]
        dists = {start: 0.0}
        while pq:
            d, curr = heapq.heappop(pq)
            if d > dists.get(curr, float('inf')):
                continue
            if curr == goal:
                return d
            for neigh in graph.get(curr, []):
                edge_d = get_edge_distance(curr, neigh)
                new_d = d + edge_d
                if new_d < dists.get(neigh, float('inf')):
                    dists[neigh] = new_d
                    heapq.heappush(pq, (new_d, neigh))
        return float('inf')

    def find_next_on_path(start, goal):
        if start == goal:
            return start
        pq = [(0.0, start)]
        dists = {start: 0.0}
        prev = {start: None}
        while pq:
            d, curr = heapq.heappop(pq)
            if d > dists.get(curr, float('inf')):
                continue
            if curr == goal:
                break
            for neigh in graph.get(curr, []):
                edge_d = get_edge_distance(curr, neigh)
                new_d = d + edge_d
                if new_d < dists.get(neigh, float('inf')):
                    dists[neigh] = new_d
                    prev[neigh] = curr
                    heapq.heappush(pq, (new_d, neigh))
        if goal not in prev or prev[goal] is None:
            return None
        curr = goal
        while prev.get(curr) is not None and prev.get(curr) != start:
            curr = prev[curr]
        return curr

    alpha = model.get("alpha", 2.0)
    beta = model.get("beta", 1.0)
    best_score = -float('inf')
    best_target = None
    for tcoord in utilities:
        util = utilities[tcoord]
        if util <= 0.0 or visited_flags.get(tcoord, True):
            continue
        dist = shortest_path_distance(current_pos, tcoord)
        if dist == float('inf') or dist <= 0.01:
            continue
        score = (util ** beta) / (dist ** alpha + 1.0)
        if score > best_score:
            best_score = score
            best_target = tcoord

    if best_target is None:
        best_utility = -1.0
        best_target_coord = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_target_coord = ncoord
                best_target = neigh_raw
        if best_target is None:
            return neighbors[0] if neighbors else None
    else:
        best_target_coord = best_target

    if best_target_coord is None:
        return neighbors[0] if neighbors else None

    if best_target_coord == current_pos:
        return best_target

    next_coord = find_next_on_path(current_pos, best_target_coord)
    if next_coord is None or next_coord == current_pos:
        return best_target

    for neigh in neighbors:
        if coord_to_tuple(neigh) == next_coord:
            return neigh

    min_d = float('inf')
    best_neigh = neighbors[0]
    for neigh in neighbors:
        nc = coord_to_tuple(neigh)
        d = get_edge_distance(nc, next_coord)
        if d < min_d:
            min_d = d
            best_neigh = neigh
    return best_neigh

def run_evaluation(data_path, checkpoint, output_path):
    model = load_model(checkpoint)
    data_path = Path(data_path)
    output_path = Path(output_path)
    output_path.parent.mkdir(parents=True, exist_ok=True)

    config_path = data_path / "eval_config.json"
    map_paths = []
    if config_path.exists():
        try:
            with open(config_path, "r") as f:
                config = json.load(f)
            if isinstance(config, list):
                map_paths = [data_path / p for p in config if isinstance(p, str)]
            elif isinstance(config, dict):
                maps_list = config.get("maps", []) or config.get("map_paths", []) or config.get("map_list", [])
                map_paths = [data_path / p for p in maps_list if isinstance(p, str)]
            print(f"Loaded {len(map_paths)} maps from eval_config.json")
        except Exception as e:
            print(f"Config load error: {e}")

    if not map_paths:
        print("No eval_config.json or empty, using 3 training maps per type for local testing.")
        map_patterns = [
            str(data_path / "maps_eval" / "*" / "*.png"),
            str(data_path / "maps_eval" / "*.png"),
            str(data_path / "maps_train" / "room" / "*.png"),
            str(data_path / "maps_train" / "tunnel" / "*.png"),
            str(data_path / "maps_train" / "outdoor" / "*.png"),
            str(data_path / "**" / "*.png")
        ]
        found_maps = []
        for pat in map_patterns:
            found = glob.glob(pat, recursive=True)
            found_maps.extend([Path(f) for f in found])
            if found_maps:
                break
        # limit to 3 per type for proxy
        type_maps = defaultdict(list)
        for m in found_maps:
            t = get_env_type(m)
            type_maps[t].append(m)
        map_paths = []
        for t in ["room", "tunnel", "outdoor"]:
            maps_for_type = type_maps.get(t, [])
            map_paths.extend(maps_for_type[:3])
        map_paths = map_paths[:9]

    if not map_paths:
        print("No maps found.")
        output = {"explored_rate": 0.0, "travel_distance": 0.0, "success_rate": 0.0, "per_episode": [], "per_type": {}, "total_episodes": 0}
        with open(output_path, "w") as f:
            json.dump(output, f, indent=2)
        return output

    print(f"Evaluating on {len(map_paths)} maps.")
    results = []
    per_type = defaultdict(lambda: {"success": 0, "dist": [], "explored": []})
    total_success = 0
    total_dist = 0.0
    total_explored = 0.0
    for map_p in map_paths:
        map_path = Path(map_p)
        env_type = get_env_type(map_path)
        try:
            env = ExplorationEnv(map_path=str(map_path))
            obs = env.reset()
            step = 0
            max_steps = 128
            done = False
            while not done and step < max_steps:
                target = select_waypoint(obs, model)
                if target is None:
                    break
                obs, info = env.step(target)
                done = info.get("done", False) or obs.get("done", False)
                step += 1
            metrics = env.get_metrics()
            success = 1 if metrics.get("success", metrics.get("explored_rate", 0.0) > 0.9999) else 0
            explored_rate = metrics.get("explored_rate", 0.0)
            travel_distance = metrics.get("travel_distance", 0.0)
            results.append({
                "map_path": str(map_path.name),
                "env_type": env_type,
                "success": success,
                "travel_distance": float(travel_distance),
                "explored_rate": float(explored_rate)
            })
            total_explored += explored_rate
            per_type[env_type]["explored"].append(explored_rate)
            per_type[env_type]["success"] += success
            if success > 0:
                total_success += 1
                total_dist += travel_distance
                per_type[env_type]["dist"].append(travel_distance)
        except Exception as e:
            print(f"Error processing {map_path}: {str(e)}")
            results.append({
                "map_path": str(map_path.name),
                "env_type": env_type,
                "success": 0,
                "travel_distance": 0.0,
                "explored_rate": 0.0
            })

    n = len(results)
    if n == 0:
        n = 1
    success_rate = total_success / n
    explored_rate_mean = total_explored / n
    travel_distance_mean = total_dist / total_success if total_success > 0 else 0.0

    per_type_dict = {}
    for t, stats in per_type.items():
        ns = len(stats["explored"])
        if ns == 0:
            continue
        sr = stats["success"] / ns
        er = sum(stats["explored"]) / ns
        td = sum(stats["dist"]) / len(stats["dist"]) if stats["dist"] else 0.0
        per_type_dict[t] = {
            "explored_rate": float(er),
            "travel_distance": float(td),
            "success_rate": float(sr)
        }

    exploration_score = sum((r["success"] * (300.0 / max(r.get("travel_distance", 1.0), 1.0))) for r in results) / n

    output = {
        "explored_rate": float(explored_rate_mean),
        "travel_distance": float(travel_distance_mean),
        "success_rate": float(success_rate),
        "per_episode": results,
        "per_type": per_type_dict,
        "total_episodes": int(n),
        "exploration_score": float(exploration_score)
    }
    with open(output_path, "w") as f:
        json.dump(output, f, indent=2)
    print("Evaluation completed with exploration_score proxy based on success and distance.")
    print(f"Success rate: {success_rate:.4f}, Explored: {explored_rate_mean:.4f}, Avg dist: {travel_distance_mean:.2f}")
    print(f"Proxy exploration_score: {exploration_score:.4f}")
    print("Local test on train subset done.")
    return output

if __name__ == "__main__":
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", type=str, default="/data")
    parser.add_argument("--checkpoint", type=str, default="checkpoints/baseline")
    parser.add_argument("--output", type=str, default="output.json")
    args = parser.parse_args()
    run_evaluation(args.data_path, args.checkpoint, args.output)
